// Get transcript segments from WayinVideo
const segments = $('4. WayinVideo — Get Transcript Results').item.json.data.transcript || [];

if (segments.length === 0) {
  throw new Error('Transcript is empty — check if the video URL is valid and publicly accessible.');
}

// Format transcript — clean and readable for GPT
const formattedTranscript = segments
  .map(s => {
    const timeInSeconds = Math.floor(s.start / 1000);
    const minutes = Math.floor(timeInSeconds / 60);
    const seconds = timeInSeconds % 60;
    const timestamp = `${minutes}:${seconds.toString().padStart(2, '0')}`;
    return `[${s.speaker} | ${timestamp}] ${s.text.trim()}`;
  })
  .join('\n');

// Total duration
const lastSegment = segments[segments.length - 1];
const totalDurationMs = lastSegment?.end || 0;
const totalMinutes = Math.round(totalDurationMs / 60000);

// Word count
const wordCount = segments.map(s => s.text).join(' ').split(/\s+/).length;

// Unique speakers
const speakers = [...new Set(segments.map(s => s.speaker))];

return [{
  json: {
    formattedTranscript,
    wordCount,
    totalMinutes,
    speakerCount: speakers.length,
    speakers: speakers.join(', '),
    videoTitle: $('1. Form — Video URL + Details').item.json['Video Title'],
    videoUrl: $('1. Form — Video URL + Details').item.json['Video URL'],
    niche: $('1. Form — Video URL + Details').item.json['Your Niche / Topic'],
    targetAudience: $('1. Form — Video URL + Details').item.json['Target Audience'],
    autoPost: $('1. Form — Video URL + Details').item.json['Auto Post to Twitter/X?']
  }
}];

// Parse AI output — extract each tweet individually
const output = $input.first().json.output || '';
const videoTitle = $('7. Code — Format Transcript').item.json.videoTitle;
const videoUrl = $('7. Code — Format Transcript').item.json.videoUrl;
const autoPost = $('7. Code — Format Transcript').item.json.autoPost;

// Generate a unique thread ID for grouping
const threadId = 'thread_' + Date.now();

// Extract all 10 tweets
const tweets = [];
for (let i = 1; i <= 10; i++) {
  const regex = new RegExp(`TWEET ${i}:\s*([\\s\\S]*?)(?=TWEET ${i + 1}:|$)`);
  const match = output.match(regex);
  if (match) {
    const tweetText = match[1].trim();
    tweets.push({
      json: {
        tweetNumber: i,
        tweetText: tweetText,
        charCount: tweetText.length,
        videoTitle: videoTitle,
        videoUrl: videoUrl,
        threadId: threadId,
        autoPost: autoPost,
        generatedOn: new Date().toISOString(),
        status: 'Draft'
      }
    });
  }
}

if (tweets.length === 0) {
  throw new Error('Could not parse tweets from AI output. Check the AI prompt output format.');
}

return tweets;
